from flask import Flask, request
from prometheus_client import start_http_server, Counter

app = Flask(__name__)
metrics = {}

@app.route('/track', methods=['GET'])
def track_request():
    user_id = request.args.get('user_id')
    session_id = request.args.get('session_id')
    path = request.path
    
    if (user_id, path) not in metrics:
        metrics[(user_id, path)] = Counter(f'request_count_{user_id}_{path}', 'Request count for user-path combination', ['user_id', 'path'])
    
    metrics[(user_id, path)].labels(user_id=user_id, path=path).inc()
    
    return "Request tracked", 200

